// ============================================================================
// φ-ARITHMETIC TOP LEVEL — Hardware Proof on QMTECH Artix-7
// ============================================================================
//
// Demonstrates φ² = φ + 1 → 0 DSP48 multiplication on real FPGA
//
// LED blink pattern shows φ-arithmetic is alive:
// - LED toggles based on phi_result bit pattern
// - Creates unique blink frequency to verify hardware operation
//
// Generated by TRI sacred-const phi-arith + hardware wrapper
// φ² + 1/φ² = 3 = TRINITY
//
// ============================================================================

`default_nettype none

module phi_arithmetic_top(
    input  wire sys_clk,    // 50 MHz oscillator (Pin U22)
    output wire led         // LED D6 (Pin T23, ACTIVE-LOW!)
);

    // ============================================================================
    // Clock Buffer
    // ============================================================================
    wire clk;
    BUFG bufg_inst (
        .I(sys_clk),
        .O(clk)
    );

    // ============================================================================
    // φ-Arithmetic Unit Instance
    // ============================================================================

    // Test inputs: Fibonacci sequence
    reg [24:0] x_input = 25'd1000;
    reg [24:0] x_prev = 25'd618;   // 1000 / φ ≈ 618 (golden ratio)

    // Phi computation results
    wire [24:0] phi_x;      // φ × x = x + x_prev = 1618
    wire [24:0] phi2_x;     // φ² × x = x + φ×x = 2618
    wire valid_out;

    // Update inputs slowly to show computation is running
    reg [31:0] input_counter;
    always @(posedge clk) begin
        input_counter <= input_counter + 1;
        if (input_counter == 32'd50000000) begin  // Every 1 second at 50 MHz
            input_counter <= 32'd0;
            x_input <= x_input + 25'd1;
            x_prev <= x_prev + 25'd1;
        end
    end

    // Instantiate φ-arithmetic unit (0 DSP48!)
    phi_arithmetic_unit #(
        .WIDTH(25)
    ) phi_inst (
        .clk(clk),
        .rst(1'b0),
        .x_in(x_input),
        .x_prev(x_prev),
        .valid_in(1'b1),
        .phi_x(phi_x),
        .phi2_x(phi2_x),
        .valid_out(valid_out)
    );

    // ============================================================================
    // LED Driver — Shows φ-arithmetic is alive
    // ============================================================================

    // Create blink pattern from phi result
    reg [24:0] led_counter;
    reg led_state;

    always @(posedge clk) begin
        led_counter <= led_counter + 1;

        // Toggle LED every ~0.5 second (25 million cycles at 50 MHz)
        if (led_counter == 25'd25000000) begin
            led_counter <= 25'd0;
            led_state <= ~led_state;
        end
    end

    // ACTIVE-LOW LED: invert output!
    // LED shows system is alive + phi computation running
    assign led = ~led_state;

endmodule

`default_nettype wire
